mapper.select:
SELECT ID, STUDENT_NAME, STUDENT_KOR, STUDENT_ENG, STUDENT_MATH , TOTAL, AVERAGE
FROM VIEW_STUDENT
WHERE ID = #{id}

mapper.update:
UPDATE TBL_STUDENT
SET STUDENT_NAME = #{studentName}, STUDENT_KOR=#{studentKor}, STUDENT_ENG=#{studentEng},STUDENT_MATH=#{studentMath}
WHERE ID = #{id}
